#!/usr/bin/env python3
# scripts/remediation_report.py
# Prints a status report for all active remediation plans across launch YAML files.
import yaml, glob, sys
from pathlib import Path
from datetime import datetime, timezone

def parse_dt(s):
    if not s:
        return None
    return datetime.fromisoformat(s.replace("Z", "+00:00"))

now = datetime.now(timezone.utc)
active = []

for launch_path in sorted(Path("docs/launches").glob("*.yaml")):
    launch = yaml.safe_load(launch_path.read_text())
    for plan in launch.get("remediation_plans", []):
        if plan.get("status") in ("open", "in_progress"):
            sla = parse_dt(plan.get("sla"))
            hours_remaining = (sla - now).total_seconds() / 3600 if sla else None
            active.append({
                "launch": launch_path.stem,
                "id": plan["id"],
                "owner": plan.get("owner", "unassigned"),
                "status": plan["status"],
                "sla": plan.get("sla", "none"),
                "hours_remaining": hours_remaining,
                "concern_summary": plan.get("concern", "")[:60].replace("\n", " "),
            })

if not active:
    print("No active remediation plans.")
    sys.exit(0)

print(f"ACTIVE REMEDIATION PLANS ({len(active)} total)\n")
print(f"{'Launch':<35} {'ID':<8} {'Owner':<25} {'Status':<12} {'SLA Remaining'}")
print("-" * 100)
for p in sorted(active, key=lambda x: x["hours_remaining"] or float("inf")):
    hr = p["hours_remaining"]
    if hr is None:
        sla_str = "no SLA"
    elif hr < 0:
        sla_str = f"OVERDUE {abs(hr):.0f}h"
    else:
        sla_str = f"{hr:.0f}h remaining"
    print(f"{p['launch']:<35} {p['id']:<8} {p['owner']:<25} {p['status']:<12} {sla_str}")
    print(f"  Concern: {p['concern_summary']}...")

Subject: [Launch Deferred] {service} {version} — {reason summary} — New target: {new date}

Team,

The Go/No-Go forum for **{service} {version}** resulted in **NO-GO** at {time} UTC.

## Block(s) raised

1. **{concern-1}** (Owner: {owner-1}, SLA: {sla-1})
   Remediation: {remediation-action-1}

2. **{concern-2}** (Owner: {owner-2}, SLA: {sla-2})
   Remediation: {remediation-action-2}

## Revised timeline

- Remediation complete by: {sla of longest block}
- Re-check Go/No-Go: {re-check date}
- Revised launch target: {new launch date}

## What is not changing

The code freeze remains in effect. No new features will be added to this release.
All completed pre-launch work remains valid unless otherwise noted.

## Status updates

I will post daily status updates in #{channel} until the remediation is resolved.
If you have questions, contact {launch-owner} or post in #{channel}.

— {launch-owner}
